export const metadata: Metadata = constructMetadata({
  title: "Polar Products",
  description: "View and manage your Polar product purchases and subscriptions.",
});

export default async function PolarProductsPage() {
  const session = await auth();

  // Define the Polar products using environment variables
  const polarProducts = [
    {
      id: env.NEXT_PUBLIC_POLAR_ONE_TIME_PRICE_ID,
      name: "One-Time Purchase",
      description: "Get lifetime access to our core features and support",
      price: "$49",
      checkoutUrl: `https://polar.sh/lacy/products/${env.NEXT_PUBLIC_POLAR_ONE_TIME_PRICE_ID}`,
    },
    {
      id: env.NEXT_PUBLIC_POLAR_SUBSCRIPTION_PRICE_ID,
      name: "Monthly Subscription",
      description: "Get monthly access to all premium features and updates",
      price: "$9.99/month",
      checkoutUrl: `https://polar.sh/lacy/subscriptions/${env.NEXT_PUBLIC_POLAR_SUBSCRIPTION_PRICE_ID}`,
    },
  ].filter((product) => !!product.id); // Only include products with valid IDs

  // Get user's purchased products if logged in
  let userProducts: any[] = [];
  if (session?.user?.id) {
    userProducts = await PaymentService.getUserPurchasedProducts(session.user.id, "polar");
  }

  return (
    <div className="container mx-auto py-10">
      <div className="flex flex-col gap-8">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Polar Products</h1>
          <p className="text-muted-foreground">View and purchase products through Polar</p>
        </div>

        {polarProducts.length > 0 ? (
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {polarProducts.map((product) => (
              <Card key={product.id} className="overflow-hidden">
                <CardHeader>
                  <CardTitle>{product.name}</CardTitle>
                  <CardDescription>{product.description}</CardDescription>
                </CardHeader>
                <CardContent className="flex flex-col gap-4">
                  <p className="font-medium">{product.price}</p>

                  {session?.user && product.id ? (
                    <PolarProductStatus
                      productId={product.id}
                      productPrice={product.price}
                      productName={product.name}
                      checkoutUrl={product.checkoutUrl}
                      buttonText="Purchase Now"
                      successText="Purchased ✓"
                    />
                  ) : (
                    <div className="text-sm text-muted-foreground">Please log in to purchase</div>
                  )}
                </CardContent>
              </Card>
            ))}
          </div>
        ) : (
          <div className="bg-muted p-4 rounded-md">
            <p className="text-muted-foreground">
              No Polar products configured. Add NEXT_PUBLIC_POLAR_ONE_TIME_PRICE_ID and/or
              NEXT_PUBLIC_POLAR_SUBSCRIPTION_PRICE_ID to your environment variables.
            </p>
          </div>
        )}

        {session?.user && userProducts.length > 0 && (
          <div className="mt-8">
            <h2 className="text-2xl font-bold mb-4">Your Purchases</h2>
            <div className="grid gap-4">
              {userProducts.map((product) => (
                <Card key={product.id}>
                  <CardContent className="pt-6">
                    <div className="flex justify-between items-center">
                      <div>
                        <h3 className="font-semibold">{product.name}</h3>
                        <p className="text-sm text-muted-foreground">
                          Purchased on {new Date(product.purchaseDate).toLocaleDateString()}
                        </p>
                      </div>
                      <div className="flex items-center text-green-600">
                        <svg
                          xmlns="http://www.w3.org/2000/svg"
                          width="20"
                          height="20"
                          viewBox="0 0 24 24"
                          fill="none"
                          stroke="currentColor"
                          strokeWidth="2"
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          className="mr-1 h-5 w-5"
                        >
                          <path d="M20 6L9 17l-5-5" />
                        </svg>
                        Active
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { signOut } from "next-auth/react";
import { useState, useTransition } from "react";
import { toast } from "sonner";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { deleteAccount } from "@/server/actions/settings";

export const DeleteAccountCard = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isPending, startTransition] = useTransition();

  const handleDeleteAccount = async () => {
    if (isPending) return;

    startTransition(async () => {
      try {
        const result = await deleteAccount();

        if (!result.success) {
          toast.error(result.error ?? "Failed to delete account");
          return;
        }

        toast.success(result.message);

        // Sign out and redirect to home page
        await signOut({ callbackUrl: "/" });
      } catch (error) {
        console.error("Delete account error:", error);
        toast.error("An unexpected error occurred");
      } finally {
        setIsOpen(false);
      }
    });
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle>Delete Account</CardTitle>
        <CardDescription>Permanently delete your account and all associated data.</CardDescription>
      </CardHeader>
      <CardContent>
        <p className="text-sm text-muted-foreground">
          This action cannot be undone. All your data will be permanently deleted.
        </p>
      </CardContent>
      <CardFooter>
        <AlertDialog open={isOpen} onOpenChange={setIsOpen}>
          <AlertDialogTrigger asChild>
            <Button variant="destructive" size="lg">
              Delete Account
            </Button>
          </AlertDialogTrigger>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
              <AlertDialogDescription>
                This action cannot be undone. This will permanently delete your account and remove
                all associated data from our servers.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel disabled={isPending}>Cancel</AlertDialogCancel>
              <AlertDialogAction
                onClick={handleDeleteAccount}
                disabled={isPending}
                className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              >
                {isPending ? "Deleting..." : "Delete Account"}
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </CardFooter>
    </Card>
  );
};

"use client";

import { useRouter } from "next/navigation";
import { useEffect, useRef, useState } from "react";
import { SEARCH_PARAM_KEYS } from "@/config/search-param-keys";
import { STATUS_CODES } from "@/config/status-codes";
import { cn } from "@/lib/utils";

interface ConnectionHighlightWrapperProps {
  children: React.ReactNode;
  connectionType: "github" | "vercel" | "cell";
}

export const ConnectionHighlightWrapper = ({
  children,
  connectionType,
}: ConnectionHighlightWrapperProps) => {
  const router = useRouter();
  const wrapperRef = useRef<HTMLDivElement>(null);
  const [highlighted, setHighlighted] = useState(false);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const code = params.get(SEARCH_PARAM_KEYS.statusCode);

    const slug = `CONNECT_${connectionType.toUpperCase()}` as keyof typeof STATUS_CODES;
    const expectedCode = STATUS_CODES[slug]?.code;
    const shouldHighlight = code?.toLowerCase() === expectedCode?.toLowerCase();

    if (shouldHighlight && wrapperRef.current) {
      // Scroll into view
      wrapperRef.current.scrollIntoView({
        behavior: "smooth",
        block: "center",
      });

      // Trigger highlight via state so React controls the style
      setHighlighted(true);

      // Remove highlight and clean up URL after animation
      const timeout = setTimeout(() => {
        setHighlighted(false);

        const url = new URL(window.location.href);
        url.searchParams.delete(SEARCH_PARAM_KEYS.statusCode);

        if (code) {
          router.replace(url.pathname + (url.search ? url.search : ""), {
            scroll: false,
          });
        }
      }, 3000);

      return () => clearTimeout(timeout);
    }
  }, [connectionType, router]);

  return (
    <div
      ref={wrapperRef}
      className={cn(
        "rounded-lg transition-all duration-700",
        highlighted &&
          "ring-2 ring-blue-500 shadow-[0_0_20px_rgba(59,130,246,0.5),0_0_40px_rgba(59,130,246,0.25)]"
      )}
    >
      {children}
    </div>
  );
};

